// --- Mock API types (these would normally be generated by gmicompile) ---

type Item struct {
	Name  string  `json:"name"`
	Value float64 `json:"value"`
}

type MockCallbacks interface {
	ListItems(pattern string) ([]Item, error)
	GetItem(name string) (*Item, error)
	CreateItem(name string, value float64) (*Item, error)
	DeleteItem(name string) error
}

// --- Mock implementation ---

type mockImpl struct {
	items map[string]Item
}

func (m *mockImpl) ListItems(pattern string) ([]Item, error) {
	var result []Item
	for _, item := range m.items {
		if pattern == "" || strings.Contains(item.Name, pattern) {
			result = append(result, item)
		}
	}
	return result, nil
}

func (m *mockImpl) GetItem(name string) (*Item, error) {
	item, ok := m.items[name]
	if !ok {
		return nil, syscall.ENOENT
	}
	return &item, nil
}

func (m *mockImpl) CreateItem(name string, value float64) (*Item, error) {
	if _, exists := m.items[name]; exists {
		return nil, syscall.EEXIST
	}
	item := Item{Name: name, Value: value}
	m.items[name] = item
	return &item, nil
}

func (m *mockImpl) DeleteItem(name string) error {
	if _, ok := m.items[name]; !ok {
		return syscall.ENOENT
	}
	delete(m.items, name)
	return nil
}

// --- Dispatch functions (these would normally be generated) ---

func dispatchListItems(callbacks unsafe.Pointer, req []byte) ([]byte, error) {
	impl := *(*MockCallbacks)(callbacks)
	var params struct {
		Pattern string `json:"pattern"`
	}
	if len(req) > 0 {
		if err := json.Unmarshal(req, &params); err != nil {
			return nil, syscall.EINVAL
		}
	}
	result, err := impl.ListItems(params.Pattern)
	if err != nil {
		return nil, err
	}
	return json.Marshal(result)
}

func dispatchGetItem(callbacks unsafe.Pointer, req []byte) ([]byte, error) {
	impl := *(*MockCallbacks)(callbacks)
	var params struct {
		Name string `json:"name"`
	}
	if len(req) > 0 {
		if err := json.Unmarshal(req, &params); err != nil {
			return nil, syscall.EINVAL
		}
	}
	result, err := impl.GetItem(params.Name)
	if err != nil {
		return nil, err
	}
	return json.Marshal(result)
}

func dispatchCreateItem(callbacks unsafe.Pointer, req []byte) ([]byte, error) {
	impl := *(*MockCallbacks)(callbacks)
	var params struct {
		Name  string  `json:"name"`
		Value float64 `json:"value"`
	}
	if len(req) > 0 {
		if err := json.Unmarshal(req, &params); err != nil {
			return nil, syscall.EINVAL
		}
	}
	result, err := impl.CreateItem(params.Name, params.Value)
	if err != nil {
		return nil, err
	}
	return json.Marshal(result)
}

func dispatchDeleteItem(callbacks unsafe.Pointer, req []byte) ([]byte, error) {
	impl := *(*MockCallbacks)(callbacks)
	var params struct {
		Name string `json:"name"`
	}
	if len(req) > 0 {
		if err := json.Unmarshal(req, &params); err != nil {
			return nil, syscall.EINVAL
		}
	}
	err := impl.DeleteItem(params.Name)
	if err != nil {
		return nil, err
	}
	return nil, nil
}

// --- Setup: register API just like generated code would ---

func setupIntegrationServer(t *testing.T) *httptest.Server {
	t.Helper()

	impl := &mockImpl{items: map[string]Item{
		"axis.0.pos-cmd": {Name: "axis.0.pos-cmd", Value: 1.23},
		"axis.1.vel":     {Name: "axis.1.vel", Value: 4.56},
	}}

	var cb MockCallbacks = impl

	meta := &apiserver.APIMeta{
		Name:       "items",
		Version:    1,
		RESTExport: true,
		Prefix:     "items",
		Funcs: []apiserver.FuncMeta{
			{Name: "list_items", Method: "GET", Path: "/items", Dispatch: dispatchListItems},
			{Name: "get_item", Method: "GET", Path: "/item/{name}", Dispatch: dispatchGetItem},
			{Name: "create_item", Method: "POST", Path: "/item", Dispatch: dispatchCreateItem},
			{Name: "delete_item", Method: "DELETE", Path: "/item/{name}", Dispatch: dispatchDeleteItem},
		},
	}

	reg := apiserver.NewRegistry()
	apiserver.RegisterMeta(meta)
	err := reg.Register("items", 1, "items0", unsafe.Pointer(&cb))
	if err != nil {
		t.Fatalf("Register: %v", err)
	}

	srv := apiserver.NewServer(reg, "localhost:0")
	ts := httptest.NewServer(srv.Handler())
	t.Cleanup(ts.Close)
	return ts
}

// --- Integration Tests ---

func TestIntegrationListItems(t *testing.T) {
	ts := setupIntegrationServer(t)

	resp, err := http.Get(ts.URL + "/api/v1/items0/items")
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		body, _ := io.ReadAll(resp.Body)
		t.Fatalf("status = %d, body = %s", resp.StatusCode, body)
	}

	var items []Item
	json.NewDecoder(resp.Body).Decode(&items)
	if len(items) != 2 {
		t.Errorf("got %d items, want 2", len(items))
	}
}

func TestIntegrationListItemsWithFilter(t *testing.T) {
	ts := setupIntegrationServer(t)

	resp, err := http.Get(ts.URL + "/api/v1/items0/items?pattern=axis.0")
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		t.Fatalf("status = %d", resp.StatusCode)
	}

	var items []Item
	json.NewDecoder(resp.Body).Decode(&items)
	if len(items) != 1 {
		t.Errorf("got %d items, want 1", len(items))
	}
	if len(items) == 1 && items[0].Name != "axis.0.pos-cmd" {
		t.Errorf("item name = %q, want axis.0.pos-cmd", items[0].Name)
	}
}

