func TestIntegrationCreateItem(t *testing.T) {
	ts := setupIntegrationServer(t)

	body := `{"name":"new-item","value":7.89}`
	resp, err := http.Post(ts.URL+"/api/v1/items0/item", "application/json", strings.NewReader(body))
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		respBody, _ := io.ReadAll(resp.Body)
		t.Fatalf("status = %d, body = %s", resp.StatusCode, respBody)
	}

	var item Item
	json.NewDecoder(resp.Body).Decode(&item)
	if item.Name != "new-item" {
		t.Errorf("name = %q, want new-item", item.Name)
	}
	if item.Value != 7.89 {
		t.Errorf("value = %f, want 7.89", item.Value)
	}

	// Verify item exists via GET
	resp2, _ := http.Get(ts.URL + "/api/v1/items0/item/new-item")
	defer resp2.Body.Close()
	if resp2.StatusCode != 200 {
		t.Errorf("created item not found: status = %d", resp2.StatusCode)
	}
}

func TestIntegrationCreateItemDuplicate(t *testing.T) {
	ts := setupIntegrationServer(t)

	body := `{"name":"axis.0.pos-cmd","value":0}`
	resp, err := http.Post(ts.URL+"/api/v1/items0/item", "application/json", strings.NewReader(body))
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 409 { // EEXIST → Conflict
		t.Errorf("status = %d, want 409", resp.StatusCode)
	}
}

func TestIntegrationDeleteItem(t *testing.T) {
	ts := setupIntegrationServer(t)

	req, _ := http.NewRequest("DELETE", ts.URL+"/api/v1/items0/item/axis.0.pos-cmd", nil)
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		body, _ := io.ReadAll(resp.Body)
		t.Fatalf("DELETE status = %d, body = %s", resp.StatusCode, body)
	}

	// Verify item is gone
	resp2, _ := http.Get(ts.URL + "/api/v1/items0/item/axis.0.pos-cmd")
	defer resp2.Body.Close()
	if resp2.StatusCode != 404 {
		t.Errorf("deleted item still found: status = %d", resp2.StatusCode)
	}
}

