func TestIntegrationCRUDSequence(t *testing.T) {
	ts := setupIntegrationServer(t)
	baseURL := ts.URL + "/api/v1/items0"

	// 1. List → 2 items
	resp, _ := http.Get(baseURL + "/items")
	var items []Item
	json.NewDecoder(resp.Body).Decode(&items)
	resp.Body.Close()
	if len(items) != 2 {
		t.Fatalf("initial list: got %d items, want 2", len(items))
	}

	// 2. Create new item
	resp, _ = http.Post(baseURL+"/item", "application/json",
		strings.NewReader(`{"name":"new","value":99}`))
	resp.Body.Close()
	if resp.StatusCode != 200 {
		t.Fatalf("create: status %d", resp.StatusCode)
	}

	// 3. List → 3 items
	resp, _ = http.Get(baseURL + "/items")
	json.NewDecoder(resp.Body).Decode(&items)
	resp.Body.Close()
	if len(items) != 3 {
		t.Fatalf("after create: got %d items, want 3", len(items))
	}

	// 4. Get new item
	resp, _ = http.Get(baseURL + "/item/new")
	var item Item
	json.NewDecoder(resp.Body).Decode(&item)
	resp.Body.Close()
	if item.Value != 99 {
		t.Errorf("get new: value = %f, want 99", item.Value)
	}

	// 5. Delete new item
	req, _ := http.NewRequest("DELETE", baseURL+"/item/new", nil)
	resp, _ = http.DefaultClient.Do(req)
	resp.Body.Close()

	// 6. List → 2 items again
	resp, _ = http.Get(baseURL + "/items")
	json.NewDecoder(resp.Body).Decode(&items)
	resp.Body.Close()
	if len(items) != 2 {
		t.Fatalf("after delete: got %d items, want 2", len(items))
	}

	// 7. Get deleted item → 404
	resp, _ = http.Get(baseURL + "/item/new")
	resp.Body.Close()
	if resp.StatusCode != 404 {
		t.Errorf("deleted item: status %d, want 404", resp.StatusCode)
	}
}

func TestIntegrationVersionMismatch(t *testing.T) {
	reg := apiserver.NewRegistry()
	impl := &mockImpl{items: map[string]Item{}}
	var cb MockCallbacks = impl
	reg.Register("v", 3, "v0", unsafe.Pointer(&cb))

	_, err := reg.GetAPIUntracked("v", "v0", 2)
	if err != syscall.EINVAL {
		t.Errorf("version mismatch: got %v, want EINVAL", err)
	}

	_, err = reg.GetAPIUntracked("v", "v0", 3)
	if err != nil {
		t.Errorf("exact version: got %v, want nil", err)
	}
}

func TestIntegrationMultipleAPIs(t *testing.T) {
	reg := apiserver.NewRegistry()
	impl := &mockImpl{items: map[string]Item{"x": {Name: "x", Value: 1}}}
	var cb MockCallbacks = impl

	meta1 := &apiserver.APIMeta{
		Name: "api1", Version: 1, RESTExport: true, Prefix: "api1",
		Funcs: []apiserver.FuncMeta{
			{Name: "list", Method: "GET", Path: "/items", Dispatch: dispatchListItems},
		},
	}
	meta2 := &apiserver.APIMeta{
		Name: "api2", Version: 1, RESTExport: true, Prefix: "api2",
		Funcs: []apiserver.FuncMeta{
			{Name: "list", Method: "GET", Path: "/items", Dispatch: dispatchListItems},
		},
	}

	apiserver.RegisterMeta(meta1)
	apiserver.RegisterMeta(meta2)

	reg.Register("api1", 1, "a1", unsafe.Pointer(&cb))
	reg.Register("api2", 1, "a2", unsafe.Pointer(&cb))

	srv := apiserver.NewServer(reg, "localhost:0")
	ts := httptest.NewServer(srv.Handler())
	defer ts.Close()

	for _, inst := range []string{"a1", "a2"} {
		resp, err := http.Get(fmt.Sprintf("%s/api/v1/%s/items", ts.URL, inst))
		if err != nil {
			t.Fatal(err)
		}
		resp.Body.Close()
		if resp.StatusCode != 200 {
			t.Errorf("%s: status %d, want 200", inst, resp.StatusCode)
		}
	}
}
